--
-- Name: log_comment_activity(); Type: FUNCTION; Schema: public; Owner: admin
--

CREATE FUNCTION public.log_comment_activity() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  INSERT INTO user_activities (
    user_id,
    action_type,
    target_id,
    target_name,
    created_at
  )
  VALUES (
    NEW.user_id,
    'comment',
    NEW.shared_trail_id,
    (
      SELECT t.name
      FROM shared_trails s
      JOIN trails t ON s.trail_id = t.id
      WHERE s.id = NEW.shared_trail_id
    ),
    NOW()
  );
  RETURN NEW;
  END;$$;


ALTER FUNCTION public.log_comment_activity() OWNER TO admin;

--
-- Name: log_favorite_activity(); Type: FUNCTION; Schema: public; Owner: admin
--

CREATE FUNCTION public.log_favorite_activity() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  INSERT INTO user_activities (
    user_id,
    action_type,
    target_id,
    target_name,
    created_at
  )
  VALUES (
    NEW.user_id,
    'favorite',
    NEW.trail_id,
    (SELECT name FROM trails WHERE id = NEW.trail_id),
    NOW()
  );

  RETURN NEW;
END;
$$;


