--
-- Name: log_trails_activity(); Type: FUNCTION; Schema: public; Owner: admin
--

CREATE FUNCTION public.log_trails_activity() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  INSERT INTO user_activities (
    user_id,
    action_type,
    target_id,
    target_name,
    created_at
  )
  VALUES (
    NEW.created_by,         
    'trail',                
    NEW.id,                 
    NEW.name,              
    NOW()
  );
  RETURN NEW;
END;
$$;


